const SB_URL   = 'https://uwnrnioshqvdhsbfxrfa.supabase.co';
const SB_KEY   = 'sb_publishable_c9gsrcgvvBpquVJ8fR7vyQ_DQqDEv_b';
const PIN_SALT = 'bf_v6_salt_2025';
const MAX_TRIES = 3;
const BLOCK_MIN = 5;
const { createClient } = supabase;
const sb = createClient(SB_URL, SB_KEY);

// Hash PIN (partagé entre login et app)
async function hashPin(pin) {
  const enc = new TextEncoder().encode(pin + PIN_SALT);
  const buf = await crypto.subtle.digest('SHA-256', enc);
  return [...new Uint8Array(buf)].map(b => b.toString(16).padStart(2,'0')).join('');
}

