window.addEventListener('load', async () => {
  console.log('BOOT START');
  const sess = getSession();
  console.log('SESSION', sess);
  await new Promise(r => setTimeout(r, 1600));
  document.getElementById('loader').classList.add('out');

  if (sess) {
    // Timeout 3s : si Supabase ne répond pas, on efface la session et on affiche le login
    const valid = await Promise.race([
      validateSession(sess),
      new Promise(r => setTimeout(() => r(false), 3000))
    ]);
    if (valid) { showApp(sess); return; }
    clearSession();
  }

  // Afficher login
  const lastRole = localStorage.getItem('bf_last_role') || 'vendeur';
  selectRole(lastRole);
  restoreSavedUser();
});

// ════════════════════════════════════════
// TRANSITION LOGIN → APP
// ════════════════════════════════════════
function showApp(sess) {
  if (['vendeur', 'leader'].includes(sess.role)) {
    document.getElementById('sLogin').style.display = 'none';
    document.getElementById('sApp').style.display = 'flex';
    S.profile = sess;
    initApp();
  } else if (['manager', 'admin'].includes(sess.role)) {
    launchManagerApp(sess);
  } else if (['chef', 'chef_famille'].includes(sess.role)) {
    launchChefApp(sess);
  } else {
    showErr('Rôle non reconnu.');
    clearSession();
  }
}

// ════════════════════════════════════════
// CODE LOGIN (Partie 1)
// ════════════════════════════════════════
/* ═══════════════════════════════════════
   CONFIG
═══════════════════════════════════════ */
// MAX_TRIES et BLOCK_MIN déclarés dans le bloc partagé ci-dessus


/* ═══ STATE ═══ */
let ROLE = '';          // rôle sélectionné dans l'UI
let pinBuf = '';        // tampon PIN
let _ltt = null;

/* ═══ ROLE SELECTION ═══ */
function selectRole(role) {
  ROLE = role;
  localStorage.setItem('bf_last_role', role);
  document.querySelectorAll('.rc').forEach(c => c.classList.remove('on'));
  const rc = document.querySelector(`.rc[data-role="${role}"]`);
  if (rc) rc.classList.add('on');

  // Panels — manager utilise désormais le panel PIN comme les autres rôles
  document.getElementById('panelPin').classList.add('on');
  document.getElementById('panelEmail').classList.remove('on');

  // Style numpad dots according to role
  document.querySelectorAll('.pdot').forEach(d => {
    d.dataset.role = role;
    d.classList.remove('on', 'err');
  });

  // Bouton couleur
  const btn = document.getElementById('btnPin');
  btn.className = 'btn-submit ' + (role === 'vendeur' ? 'bs-v' : role === 'leader' ? 'bs-l' : role === 'chef' ? 'bs-c' : 'bs-m');
  btn.disabled = true;

  // Reset PIN buffer
  pinBuf = '';
  renderDots();

  // Clear errors
  hideErr();
  hideBlocked();

  // Focus
  setTimeout(() => {
    const i = document.getElementById('pinIdent');
    if (!i.value) i.focus();
    else focusPad();
  }, 200);
}

/* ═══ SAVED USER HINT ═══ */
function restoreSavedUser() {
  const saved = JSON.parse(localStorage.getItem('bf_saved_user') || 'null');
  if (!saved) return;
  const hint = document.getElementById('savedHint');
  hint.dataset.ident = saved.ident;
  hint.dataset.role = saved.role;
  document.getElementById('savedName').textContent = saved.nom + ' (' + saved.ident + ')';
  hint.classList.add('show');
}
function applySaved() {
  const hint = document.getElementById('savedHint');
  const ident = hint.dataset.ident;
  const role = hint.dataset.role;
  if (!ident || !role) return;
  selectRole(role);
  document.getElementById('pinIdent').value = ident;
  focusPad();
}

function onIdentChange() {
  pinBuf = '';
  renderDots();
  document.getElementById('btnPin').disabled = true;
  hideErr();
}

function focusPad() {
  // On mobile, having a numeric input focused causes issues
  // The numpad is custom so just scroll into view
  document.getElementById('numpad').scrollIntoView({ behavior: 'smooth', block: 'nearest' });
}

/* ═══ PIN NUMPAD ═══ */
function nkPress(k) {
  if (pinBuf.length >= 4) return;
  pinBuf += k;
  renderDots();
  if (pinBuf.length === 4) {
    const ident = document.getElementById('pinIdent').value.trim();
    if (ident) {
      document.getElementById('btnPin').disabled = false;
      setTimeout(() => doLoginPin(), 150);
    }
  }
}
function nkDel() {
  pinBuf = pinBuf.slice(0, -1);
  renderDots();
  document.getElementById('btnPin').disabled = true;
  hideErr();
}
function renderDots() {
  for (let i = 0; i < 4; i++) {
    const d = document.getElementById('pd' + i);
    d.classList.toggle('on', i < pinBuf.length);
  }
}
function shakeDots() {
  document.querySelectorAll('.pdot').forEach(d => {
    d.classList.remove('on');
    d.classList.add('err');
    setTimeout(() => d.classList.remove('err'), 400);
  });
}

/* ═══════════════════════════════
   BRUTE-FORCE PROTECTION (client)
   Les vraies limites doivent aussi
   être appliquées côté Supabase/Edge.
═══════════════════════════════ */
function getAttempts(ident) {
  const data = JSON.parse(localStorage.getItem('bf_attempts_' + ident) || '{"n":0,"until":0}');
  return data;
}
function incrAttempts(ident) {
  const d = getAttempts(ident);
  d.n += 1;
  if (d.n >= MAX_TRIES) d.until = Date.now() + BLOCK_MIN * 60 * 1000;
  localStorage.setItem('bf_attempts_' + ident, JSON.stringify(d));
  // Log dans Supabase (best-effort, silencieux)
  sb.from('admin_logs').insert({
    event_type: 'login_failed',
    identifiant: ident,
    role_claimed: ROLE,
    details: { attempt: d.n, blocked: d.n >= MAX_TRIES }
  }).then(() => {});
  return d;
}
function resetAttempts(ident) {
  localStorage.removeItem('bf_attempts_' + ident);
}
function loginIsBlocked(ident) {
  const d = getAttempts(ident);
  if (d.n >= MAX_TRIES && d.until > Date.now()) return d.until;
  if (d.n >= MAX_TRIES && d.until <= Date.now()) { resetAttempts(ident); return false; }
  return false;
}

/* ═══════════════════════════════
   LOGIN — VENDEUR / LEADER (PIN)
═══════════════════════════════ */
async function doLoginPin() {
  const ident = document.getElementById('pinIdent').value.trim().toLowerCase();
  if (!ident) { showErr('Entrez votre identifiant.'); return; }
  if (pinBuf.length !== 4) { showErr('Entrez votre PIN (4 chiffres).'); return; }

  // Vérifier blocage
  const blockedUntil = loginIsBlocked(ident);
  if (blockedUntil) { showBlocked(blockedUntil); shakeDots(); return; }

  setLoading('btnPin', true);
  hideErr(); hideBlocked();

  try {
    const pinHash = await hashPin(pinBuf);

    // ① Récupérer le user depuis Supabase — SANS faire confiance au rôle UI
    const { data: rows, error } = await sb
      .from('users')
      .select('id, nom, identifiant, role, leader_id, actif, pin_hash')
      .eq('identifiant', ident)
      .eq('actif', true)
      .limit(1);

    if (error || !rows || rows.length === 0) {
      handleFailedAttempt(ident);
      return;
    }

    const user = rows[0];

    // ② Comparer le hash PIN
    if (user.pin_hash !== pinHash) {
      handleFailedAttempt(ident);
      return;
    }

    // ③ CRITIQUE : vérifier que le rôle RÉEL correspond au rôle sélectionné
    const realRole = user.role;
    // chef et chef_famille sont équivalents (UI utilise 'chef', DB peut stocker l'un ou l'autre)
    const normalizeRole = r => (['chef','chef_famille'].includes(r) ? 'chef' : r);
    if (normalizeRole(realRole) !== normalizeRole(ROLE)) {
      // Rôle frauduleux — log + refus générique
      await sb.from('admin_logs').insert({
        event_type: 'role_mismatch',
        identifiant: ident,
        role_claimed: ROLE,
        details: { real_role: realRole }
      });
      handleFailedAttempt(ident, true);
      return;
    }

    // ✅ SUCCÈS
    resetAttempts(ident);
    await logSuccess(ident, realRole);

    // Sauvegarder pour auto-remplissage
    localStorage.setItem('bf_saved_user', JSON.stringify({ ident: user.identifiant, nom: user.nom, role: realRole }));

    // Créer session locale sécurisée
    const session = buildSession(user);
    saveSession(session);

    lToast('✅ Bienvenue ' + user.nom + ' !', 'success');
    await new Promise(r => setTimeout(r, 700));
    redirectByRole(realRole, session);

  } catch (e) {
    console.error(e);
    showErr('Erreur de connexion. Réessayez.');
  } finally {
    setLoading('btnPin', false);
  }
}

function handleFailedAttempt(ident, silent = false) {
  const d = incrAttempts(ident);
  shakeDots();
  pinBuf = '';
  renderDots();
  document.getElementById('btnPin').disabled = true;

  if (d.n >= MAX_TRIES) {
    showBlocked(d.until);
  } else {
    const remaining = MAX_TRIES - d.n;
    showErr('Identifiants invalides.' + (remaining > 0 ? ' (' + remaining + ' essai(s) restant)' : ''));
  }
}

/* ═══════════════════════════════
   LOGIN — MANAGER (Email + MDP)
═══════════════════════════════ */
async function doLoginEmail() {
  const email = document.getElementById('mgrEmail').value.trim().toLowerCase();
  const pwd   = document.getElementById('mgrPwd').value;
  if (!email || !pwd) { showErr('Remplissez tous les champs.'); return; }

  const blockedUntil = loginIsBlocked('mgr_' + email);
  if (blockedUntil) { showBlocked(blockedUntil); return; }

  setLoading('btnEmail', true);
  hideErr(); hideBlocked();

  try {
    // ① Auth Supabase (email + mot de passe)
    const { data: authData, error: authErr } = await sb.auth.signInWithPassword({ email, password: pwd });

    if (authErr || !authData?.user) {
      console.error('Auth error:', authErr);
      const d = incrAttempts('mgr_' + email);
      if (d.n >= MAX_TRIES) showBlocked(d.until);
      else showErr('Email ou mot de passe incorrect. (' + (MAX_TRIES - d.n) + ' essai(s) restant)');
      return;
    }

    // ② Chercher le profil dans la table users par identifiant = email
    let user = null;

    const { data: byIdent, error: e1 } = await sb
      .from('users')
      .select('id, nom, identifiant, role, actif, leader_id')
      .eq('identifiant', email)
      .eq('actif', true)
      .limit(1);

    if (!e1 && byIdent?.length) {
      user = byIdent[0];
    }

    // Fallback : chercher par identifiant sans le filtre actif (manager peut être mal configuré)
    if (!user) {
      const { data: byIdent2 } = await sb
        .from('users')
        .select('id, nom, identifiant, role, actif, leader_id')
        .eq('identifiant', email)
        .limit(1);
      if (byIdent2?.length) user = byIdent2[0];
    }

    // Dernier fallback : chercher par role=manager ou Manager parmi les actifs
    if (!user) {
      const { data: byRole } = await sb
        .from('users')
        .select('id, nom, identifiant, role, actif, leader_id')
        .in('role', ['manager', 'admin', 'Manager', 'Admin'])
        .eq('actif', true)
        .limit(1);
      if (byRole?.length) user = byRole[0];
    }

    if (!user) {
      await sb.auth.signOut();
      showErr('Compte manager introuvable. Vérifiez la table users.');
      return;
    }

    // ③ Vérifier que le rôle est bien manager/admin (insensible à la casse)
    const roleNorm = (user.role || '').toLowerCase();
    if (!['manager', 'admin'].includes(roleNorm)) {
      await sb.auth.signOut();
      showErr('Ce compte n\'a pas les droits manager.');
      return;
    }
    // Normaliser le rôle pour la session
    user.role = roleNorm;

    if (!user.actif) {
      await sb.auth.signOut();
      showErr('Ce compte est désactivé.');
      return;
    }

    // ✅ SUCCÈS
    resetAttempts('mgr_' + email);

    const session = buildSession(user, authData.session?.access_token);
    saveSession(session);

    lToast('✅ Bienvenue ' + user.nom + ' !', 'success');
    await new Promise(r => setTimeout(r, 700));
    redirectByRole(user.role, session);

  } catch (e) {
    console.error('doLoginEmail error:', e);
    showErr('Erreur de connexion : ' + (e.message || 'réessayez.'));
  } finally {
    setLoading('btnEmail', false);
  }
}

/* ═══ SESSION ═══ */
function buildSession(user, token = null) {
  return {
    id: user.id,
    nom: user.nom,
    identifiant: user.identifiant,
    role: user.role,          // rôle validé côté backend
    leader_id: user.leader_id || null,
    token,                    // JWT Supabase (managers)
    ts: Date.now()
  };
}
function saveSession(sess) {
  // Stocké sous la clé commune attendue par bome_part2_app.html
  localStorage.setItem('bf_session', JSON.stringify({ profile: sess }));
  // Copie pour le dashboard manager
  if (['manager', 'admin'].includes(sess.role)) {
    localStorage.setItem('bf_mgr', JSON.stringify({ ok: true, nom: sess.nom }));
  }
}
function getSession() {
  try {
    const s = JSON.parse(localStorage.getItem('bf_session') || 'null');
    if (!s?.profile) return null;
    // Expiration 12h
    if (Date.now() - (s.profile.ts || 0) > 12 * 3600 * 1000) { clearSession(); return null; }
    return s.profile;
  } catch { return null; }
}
function clearSession() {
  localStorage.removeItem('bf_session');
  localStorage.removeItem('bf_mgr');
}
async function validateSession(sess) {
  // Revalider que le user est toujours actif et que son rôle n'a pas changé
  try {
    const { data, error } = await sb.from('users')
      .select('role, actif')
      .eq('id', sess.id)
      .limit(1)
      .single();
    console.log('session check', data, error);
    if (error || !data) return false;
    return data.actif === true && (data.role || '').toLowerCase() === (sess.role || '').toLowerCase();
  } catch (e) { console.error('validateSession error', e); return false; }
}

/* ═══ REDIRECT / LAUNCH APP ═══ */
function redirectByRole(role, sess) {
  if (['vendeur', 'leader'].includes(role)) {
    showApp(sess);
  } else if (['manager', 'admin'].includes(role)) {
    launchManagerApp(sess);
  } else if (['chef', 'chef_famille'].includes(role)) {
    launchChefApp(sess);
  } else {
    showErr('Rôle non reconnu.');
    clearSession();
  }
}
/* ── Transition visuelle pendant le chargement manager ── */
function showTransition(nom, role) {
  const ld = document.getElementById('loader');
  if (ld) { ld.classList.remove('out'); ld.style.opacity = '1'; ld.style.pointerEvents = 'auto'; }
}

/* ── Fallback : injecter le shell manager si le fichier externe est absent ── */
function injectManagerShell(sess) {
  const html = getManagerShellHTML(sess);
  document.open(); document.write(html); document.close();
}

/* ── Lancer le dashboard manager inline ── */
function launchManagerApp(sess) {
  // Navigation directe — évite document.write() qui cause des conflits de scope
  // La session est déjà dans localStorage, le dashboard la lira au démarrage
  showTransition(sess.nom, sess.role);
  setTimeout(() => {
    window.location.href = 'bome_manager_dashboard.html';
  }, 900);
}

/* ── Lancer le dashboard chef de famille ── */
function launchChefApp(sess) {
  showTransition(sess.nom, sess.role);
  setTimeout(() => {
    window.location.href = 'bome_chef_dashboard.html';
  }, 900);
}


