/* ═══ UI HELPERS ═══ */
function showErr(msg) {
  const b = document.getElementById('errBox');
  document.getElementById('errTxt').textContent = msg;
  b.classList.add('show');
}
function hideErr() { document.getElementById('errBox').classList.remove('show'); }

function showBlocked(until) {
  const rem = Math.ceil((until - Date.now()) / 60000);
  document.getElementById('blockedTxt').textContent =
    'Trop de tentatives. Réessayez dans ' + rem + ' minute' + (rem > 1 ? 's' : '') + '.';
  document.getElementById('blockedBox').classList.add('show');
  // Actualiser le compte à rebours
  clearInterval(window._blockTimer);
  window._blockTimer = setInterval(() => {
    const r = Math.ceil((until - Date.now()) / 60000);
    if (r <= 0) {
      clearInterval(window._blockTimer);
      hideBlocked();
    } else {
      document.getElementById('blockedTxt').textContent =
        'Trop de tentatives. Réessayez dans ' + r + ' minute' + (r > 1 ? 's' : '') + '.';
    }
  }, 15000);
}
function hideBlocked() {
  document.getElementById('blockedBox').classList.remove('show');
  clearInterval(window._blockTimer);
}

function setLoading(btnId, on) {
  const btn = document.getElementById(btnId);
  btn.disabled = on;
  btn.classList.toggle('loading', on);
}

function togglePwd() {
  const inp = document.getElementById('mgrPwd');
  const eye = document.getElementById('eyeBtn');
  if (inp.type === 'password') { inp.type = 'text'; eye.textContent = '🙈'; }
  else { inp.type = 'password'; eye.textContent = '👁️'; }
}

function lToast(msg, type = 'success') {
  const t = document.getElementById('lToast');
  if (_ltt) { clearTimeout(_ltt); t.classList.remove('show'); void t.offsetWidth; }
  t.textContent = msg; t.className = 'toast ' + type; void t.offsetWidth;
  t.classList.add('show');
  _ltt = setTimeout(() => { t.classList.remove('show'); _ltt = null; }, 2800);
}

