/* ═══ SQL INSERT MODAL ═══ */
let _sqlInsertTemplate = null; // sauvegarde du template original

async function openSqlInsert() {
  document.getElementById('sqlInsertBg').classList.add('open');

  // Sauvegarder le template original une seule fois
  const pre = document.getElementById('sqlInsertPre');
  if (!_sqlInsertTemplate) _sqlInsertTemplate = pre.textContent;

  // Calculer les vrais hashes en temps réel
  const pins = { '0000': null, '1234': null, '2222': null, '3333': null, '5678': null, '9999': null };
  for (const pin of Object.keys(pins)) {
    pins[pin] = await hashPin(pin);
  }

  // Afficher les hashes
  const disp = document.getElementById('sqlHashDisplay');
  disp.textContent =
    'PIN 0000  →  ' + pins['0000'] + '\n' +
    'PIN 1234  →  ' + pins['1234'] + '\n' +
    'PIN 2222  →  ' + pins['2222'] + '\n' +
    'PIN 3333  →  ' + pins['3333'] + '\n' +
    'PIN 5678  →  ' + pins['5678'] + '\n' +
    'PIN 9999  →  ' + pins['9999'];

  // Toujours repartir du template original pour éviter les doubles remplacements
  let sql = _sqlInsertTemplate;
  sql = sql.replace('___HASH_0000___', pins['0000']);
  sql = sql.replace('___HASH_1234___', pins['1234']);
  sql = sql.replace('___HASH_2222___', pins['2222']);
  sql = sql.replace('___HASH_3333___', pins['3333']);
  sql = sql.replace('___HASH_5678___', pins['5678']);
  sql = sql.replace('___HASH_9999___', pins['9999']);
  pre.textContent = sql;
}
function closeSqlInsert() { document.getElementById('sqlInsertBg').classList.remove('open'); }
function copySqlInsert() {
  const txt = document.getElementById('sqlInsertPre').textContent;
  navigator.clipboard.writeText(txt)
    .then(() => lToast('✅ SQL copié !', 'success'))
    .catch(() => lToast('Erreur copie — sélectionnez manuellement.', 'error'));
}

