// ════ LOAD DATA ════
async function loadJournees(){
  if(!S.profile)return;
  const{data,error}=await sb.from('journees').select('*, signatures(id,signed_at,leader_id)').eq('vendeur_id',S.profile.id).order('date_journee',{ascending:false});
  console.log('loadJournees error',error);
  if(data)S.journees=data;
}
async function loadTeam(){
  if(!S.profile||!isLeader())return;
  const{data:team,error:teamErr}=await sb.from('users').select('*').eq('leader_id',S.profile.id).eq('actif',true);
  console.log('loadTeam error',teamErr);
  if(team)S.team=team;
  if(S.team.length){
    const ids=S.team.map(m=>m.id);
    const{data:jours}=await sb.from('journees').select('*, users(nom,identifiant), signatures(id,signed_at)').in('vendeur_id',ids).order('date_journee',{ascending:false});
    S.teamJ=jours||[];
    const unsig=S.teamJ.filter(j=>j.locked&&!j.valide);
    const b=document.getElementById('eqBadge');
    if(unsig.length){b.style.display='flex';b.textContent=unsig.length>9?'9+':unsig.length;}
    else b.style.display='none';
  }
  const{data:rets,error:retsErr}=await sb.from('retraits').select('*').eq('leader_id',S.profile.id).order('created_at',{ascending:false});
  console.log('loadTeam error',retsErr);
  if(rets)S.retraits=rets;
}

// ════ COMMISSIONS ════
function computeComm(s,isF){
  const tot=s*PRICE,me=s*50,lead=isF?s*COMM_L:0,ent=s*600;
  return{tot,me,lead,ent};
}

// ════ CRÉATION FILLEUL ════
async function createFilleul(){
  const nom=document.getElementById('fNom').value.trim();
  const ident=document.getElementById('fIdent').value.trim().toLowerCase();
  const pin=document.getElementById('fPin').value.trim();
  if(!nom||!ident||!pin){toast('⚠️ Remplissez tous les champs','error');return;}
  if(pin.length!==4||isNaN(pin)){toast('⚠️ PIN : 4 chiffres requis','error');return;}
  const{data:exist}=await sb.from('users').select('id').eq('identifiant',ident).limit(1);
  if(exist&&exist.length){toast('❌ Identifiant déjà utilisé','error');return;}
  showLoad('Création du filleul…');
  const h=await hashPin(pin);
  const{error}=await sb.from('users').insert({nom,identifiant:ident,pin_hash:h,role:'vendeur',leader_id:S.profile.id,created_by:S.profile.id,actif:true});
  hideLoad();if(error){toast('❌ '+error.message,'error');return;}
  document.getElementById('fNom').value='';document.getElementById('fIdent').value='';document.getElementById('fPin').value='';
  await loadTeam();renderEquipe();toast('✅ Filleul créé : '+nom,'success');
}

