// ════ BLOCAGE ════
function isBlocked(){if(S.started)return false;if(!S.journees.length)return false;return !S.journees[0].bilan_fait;}
function checkBlock(){
  const b=isBlocked();document.getElementById('blkAlert').style.display=b?'block':'none';
  if(!b&&S.journees.length>0&&!S.started&&S.journees[0].restants>0){
    document.getElementById('raBlock').style.display='block';document.getElementById('stockBlock').style.display='none';
    document.getElementById('raRest').value=S.journees[0].restants;document.getElementById('raAdd').value=0;calcRA();
  }else{document.getElementById('raBlock').style.display='none';document.getElementById('stockBlock').style.display=b?'none':'block';}
}
function calcRA(){const r=parseInt(document.getElementById('raRest').value)||0,a=parseInt(document.getElementById('raAdd').value)||0;document.getElementById('raTotal').textContent=r+a;}
function applyRA(){const r=parseInt(document.getElementById('raRest').value)||0,a=parseInt(document.getElementById('raAdd').value)||0;document.getElementById('stockQty').value=r+a;document.getElementById('raBlock').style.display='none';document.getElementById('stockBlock').style.display='block';toast('✅ Stock : '+(r+a)+' unités','success');}
function ignoreRA(){document.getElementById('raBlock').style.display='none';document.getElementById('stockBlock').style.display='block';}

// ════ JOURNÉE ════
function startDay(){
  if(isBlocked()){toast('🔒 Traitez le bilan avant','error');return;}
  if(S.started){toast('⚠️ Clôturez d\'abord','error');return;}
  const v=parseInt(document.getElementById('stockQty').value)||0;
  if(v<=0){toast('⚠️ Stock invalide','error');return;}
  S.stock=v;S.objectif=Math.max(0,parseInt(document.getElementById('inputObjectif').value)||0);S.N={cash:0,wave:0,orange:0};S.pertes=0;S.started=true;S.openTs=Date.now();
  document.getElementById('btnCorrect').style.display='flex';
  startAutoWatch();startSince();upd();toast('✅ Journée ouverte — '+v+' unités','success');
}
function sold(){return S.N.cash+S.N.wave+S.N.orange;}
function used(){return sold();}
function ad(t){if(!S.started){toast("Ouvrez d'abord la journée",'info');return;}if(used()>=S.stock){toast('⚠️ Stock épuisé !','error');return;}S.N[t]++;S.history.push(t);if(S.history.length>10)S.history.shift();bumpEl(t+'N');upd();}
function rm(t){if(S.N[t]<=0)return;S.N[t]--;bumpEl(t+'N');upd();}
function annuler(){if(!S.history.length)return;const t=S.history.pop();if(S.N[t]>0)S.N[t]--;bumpEl(t+'N');upd();toast('↩️ Annulé','info');}
function sc(t){if(!S.started){toast("Ouvrez d'abord",'info');return;}const el=document.getElementById(t+'N');let v=parseInt(el.value)||0;if(v<0)v=0;const o=used()-S.N[t];if(o+v>S.stock){v=S.stock-o;toast('⚠️ Limité à '+S.stock,'error');}S.N[t]=v;upd();}
function adP(){if(!S.started){toast("Ouvrez d'abord la journée",'info');return;}if(!S.pertes)S.pertes=0;S.pertes++;bumpEl('pertesN');upd();}
function rmP(){if(!S.pertes||S.pertes<=0)return;S.pertes--;bumpEl('pertesN');upd();}
function scP(){if(!S.started){toast("Ouvrez d'abord",'info');return;}const el=document.getElementById('pertesN');let v=parseInt(el.value)||0;if(v<0)v=0;S.pertes=v;upd();}
function bumpEl(id){const el=document.getElementById(id);el.classList.remove('bump');void el.offsetWidth;el.classList.add('bump');setTimeout(()=>el.classList.remove('bump'),280);}

// Correction avant clôture
function doCorrect(){
  if(!S.started){toast('Aucune journée en cours','error');return;}
  const type=document.getElementById('corrType').value;
  const val=parseInt(document.getElementById('corrVal').value)||0;
  const errEl=document.getElementById('corrErr');errEl.style.display='none';
  if(val<0){errEl.textContent='Valeur invalide.';errEl.style.display='block';return;}
  const o=used()-S.N[type];if(o+val>S.stock){errEl.textContent='Dépasse le stock ('+S.stock+').';errEl.style.display='block';return;}
  S.N[type]=val;closeMod('mCorrect');upd();toast('✅ Quantité corrigée','success');
}

function upd(){
  const s=sold(),isF=!!(S.profile?.leader_id),r=computeComm(s,isF),rem=Math.max(0,S.stock-used());
  ['cash','wave','orange'].forEach(k=>document.getElementById(k+'N').value=S.N[k]);
  document.getElementById('cashAmt').textContent=fmt(S.N.cash*PRICE)+' FCFA';
  document.getElementById('waveAmt').textContent=fmt(S.N.wave*PRICE)+' FCFA';
  document.getElementById('orangeAmt').textContent=fmt(S.N.orange*PRICE)+' FCFA';
  const pEl=document.getElementById('pertesN');if(pEl)pEl.value=S.pertes||0;
  const pAmt=document.getElementById('pertesAmt');if(pAmt)pAmt.textContent=(S.pertes||0)+' unité(s) abîmée(s)';
  document.getElementById('fStock').textContent=S.stock;
  document.getElementById('fSold').textContent=s;
  document.getElementById('fRemain').textContent=rem;
  document.getElementById('fRemain').style.color=rem<=2?'var(--red)':'var(--ink)';
  document.getElementById('rStock').textContent=S.stock;
  document.getElementById('rSold').textContent=s;
  document.getElementById('rRemain').textContent=rem;
  document.getElementById('totalD').textContent=fmt(r.tot)+' F';
  document.getElementById('entD').textContent=fmt(r.ent)+' F';
  document.getElementById('meD').textContent=fmt(r.me)+' F';
  // ── Barre objectif ──
  (function(){
    const bar=document.getElementById('objBar');if(!bar)return;
    if(!S.objectif||S.objectif<=0){bar.innerHTML='';return;}
    const s=sold(),pct=Math.min(100,Math.round(s/S.objectif*100));
    const col=pct>=100?'var(--accent)':pct>=60?'var(--amber)':'var(--blue)';
    bar.innerHTML='<div style="background:var(--card);border:1px solid var(--border);border-radius:12px;padding:10px 13px;box-shadow:var(--sh)">'
      +'<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:7px">'
      +'<span style="font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.08em;color:var(--muted)">Objectif du jour</span>'
      +'<span style="font-family:JetBrains Mono,monospace;font-size:12px;font-weight:800;color:'+col+'">'+s+' / '+S.objectif+' u. ('+pct+'%)</span>'
      +'</div>'
      +'<svg width="100%" height="10" style="border-radius:6px;overflow:hidden;display:block">'
      +'<rect x="0" y="0" width="100%" height="10" fill="var(--border)"/>'
      +'<rect x="0" y="0" width="'+pct+'%" height="10" fill="'+col+'" style="transition:width .4s ease"/>'
      +'</svg>'
      +'</div>';
  })();
  const btnA=document.getElementById('btnAnnuler');if(btnA){btnA.disabled=!S.history.length;btnA.style.opacity=S.history.length?'1':'.35';}
  saveLocal();
}
// ════ TIMERS ════
function startSince(){
  if(S.sinceInt)clearInterval(S.sinceInt);
  S.sinceInt=setInterval(()=>{
    if(!S.started||!S.openTs){clearInterval(S.sinceInt);document.getElementById('openSince').textContent='—';return;}
    const e=Math.floor((Date.now()-S.openTs)/1000);
    document.getElementById('openSince').textContent=pad(Math.floor(e/3600))+':'+pad(Math.floor((e%3600)/60))+':'+pad(e%60);
  },1000);
}
function startAutoWatch(){
  if(S.autoInt)clearInterval(S.autoInt);
  S.autoInt=setInterval(()=>{
    if(!S.started||!S.openTs)return;
    const rem=86400000-(Date.now()-S.openTs);
    if(rem<=3600000&&rem>0){document.getElementById('autoAlert').style.display='block';const sec=Math.floor(rem/1000);document.getElementById('autoTimer').textContent=pad(Math.floor(sec/3600))+':'+pad(Math.floor((sec%3600)/60))+':'+pad(sec%60);}
    if(rem<=0){clearInterval(S.autoInt);doAutoClose();}
  },1000);
}

// ════ CLÔTURE ════
async function terminerJournee(auto=false){
  if(!S.started){toast('Aucune journée en cours','error');return;}
  const s=sold(),isF=!!(S.profile?.leader_id),r=computeComm(s,isF);
  const now=new Date();
  showLoad('Sauvegarde…');
  const{data,error}=await sb.from('journees').insert({
    vendeur_id:S.profile.id,
    date_journee:now.toISOString().split('T')[0],
    date_label:now.toLocaleDateString('fr-FR',{weekday:'long',day:'numeric',month:'long',year:'numeric'}),
    stock_initial:S.stock,vendu_cash:S.N.cash,vendu_wave:S.N.wave,vendu_orange:S.N.orange,pertes:S.pertes||0,
    total_vendu:s,restants:Math.max(0,S.stock-used()),
    total_fcfa:r.tot,part_entreprise:Math.round(r.tot*.6),part_entreprise_nette:r.ent,
    commission_vendeur:r.me,commission_leader:r.lead,
    auto_cloture:auto,bilan_fait:false,locked:true,objectif:S.objectif||0,
    open_ts:new Date(S.openTs).toISOString(),close_ts:now.toISOString(),prix_unitaire:PRICE
  }).select().single();
  hideLoad();if(error){toast('❌ '+error.message,'error');return;}
  S.journees.unshift(data);resetDay();
  toast(auto?'⏰ Clôture automatique !':'🔒 Journée terminée !','success');renderHist();
}
async function doAutoClose(){S.started=true;await terminerJournee(true);}
function resetDay(){
  S.started=false;S.stock=0;S.N={cash:0,wave:0,orange:0};S.pertes=0;S.openTs=null;
  if(S.autoInt)clearInterval(S.autoInt);if(S.sinceInt)clearInterval(S.sinceInt);
  document.getElementById('autoAlert').style.display='none';
  document.getElementById('btnCorrect').style.display='none';
  document.getElementById('stockQty').value='';
  document.getElementById('openSince').textContent='—';
  localStorage.removeItem('bf_cur');upd();checkBlock();
}

