// ════ HISTORIQUE FILTRE MOIS ════
async function loadMoisDispos(){
  if(!S.profile)return;
  // Fetch all journees dates (already in S.journees + may need refresh)
  // Derive distinct YYYY-MM from S.journees
  const sel=document.getElementById("filtreMois");if(!sel)return;
  const current=sel.value;
  const months=[...new Set(S.journees.map(j=>j.date_journee?j.date_journee.slice(0,7):"").filter(Boolean))].sort().reverse();
  sel.innerHTML='<option value="">Tous les mois</option>'
    +months.map(m=>{
      const[y,mo]=m.split("-");
      const label=new Date(+y,+mo-1,1).toLocaleDateString("fr-FR",{month:"long",year:"numeric"});
      return '<option value="'+m+'"'+(m===current?' selected':'')+'>'+label+'</option>';
    }).join("");
}
async function loadJourneesFiltre(mois){
  if(!S.profile)return;
  const ld=document.getElementById("histLoad");if(ld)ld.style.display="block";
  let q=sb.from("journees").select("*, signatures(id,signed_at,leader_id)").eq("vendeur_id",S.profile.id).order("date_journee",{ascending:false});
  if(mois){
    const[y,m]=mois.split("-");
    const first=mois+"-01";
    const last=new Date(+y,+m,0).toISOString().split("T")[0];
    q=q.gte("date_journee",first).lte("date_journee",last);
  }
  const{data}=await q;
  if(data)S.journees=data;
  if(ld)ld.style.display="none";
  renderHist();
}
function onFiltreMois(){
  const mois=document.getElementById("filtreMois")?.value||"";
  loadJourneesFiltre(mois);
}

