async function doRetrait(){
  const mt=parseInt(document.getElementById('retMt').value)||0;const note=document.getElementById('retNote').value.trim();
  const errEl=document.getElementById('retErr');errEl.style.display='none';
  if(mt<=0){errEl.textContent='Montant invalide.';errEl.style.display='block';return;}
  const tC=S.teamJ.reduce((a,j)=>a+(j.commission_leader||0),0),tR=S.retraits.reduce((a,r)=>a+(r.montant||0),0);
  if(mt>tC-tR){errEl.textContent='Dépasse le disponible.';errEl.style.display='block';return;}
  showLoad('Enregistrement…');
  const{data,error}=await sb.from('retraits').insert({leader_id:S.profile.id,montant:mt,note:note||null}).select().single();
  hideLoad();if(error){toast('❌ '+error.message,'error');return;}
  S.retraits.unshift(data);closeMod('mRet');renderEquipe();toast('✅ Retrait de '+fmt(mt)+' F enregistré','success');
}

