    +'• Total          : '+fmt(j.total_fcfa)+' F\n• 💚 Ma part     : '+fmt(j.commission_vendeur)+' F (40%)\n\n'
    +'━━━━━━━━━━━━━━━━━━\n'+(ts?'⏱️ *Envoyé le :* '+ts:"⏳ _Heure fixée à l'envoi_");
