// ════ BILAN CHART ════
function _btShow(v,l){var t=document.getElementById('bilanTip');if(t){t.textContent=v+' u. · '+l;t.style.opacity='1';}}
function _btHide(){var t=document.getElementById('bilanTip');if(t)t.style.opacity='0';}
function buildBilanChart(sorted){
  if(!sorted||!sorted.length)return '';
  var W=400,H=90,n=sorted.length;
  var maxV=Math.max.apply(null,sorted.map(function(j){return j.total_vendu||0;}));
  if(!maxV)return '';
  var barW=Math.max(6,Math.floor((W-8*(n+1))/n));
  var gap=Math.floor((W-barW*n)/(n+1));
  var bars=sorted.map(function(j,idx){
    var v=j.total_vendu||0;
    var h=Math.max(3,Math.round(v/maxV*H));
    var x=gap+idx*(barW+gap);
    var y=H-h;
    var dl=(j.date_label||j.date_journee||'').replace(/['"><&]/g,'');
    return '<rect x="'+x+'" y="'+y+'" width="'+barW+'" height="'+h+'" rx="3"'
      +' style="fill:var(--accent);cursor:pointer;opacity:.85;transition:opacity .12s"'
      +' onmouseenter="_btShow('+v+',&quot;'+dl+'&quot;)" onmouseleave="_btHide()"/>';
  }).join('');
  return '<div style="background:var(--card);border:1px solid var(--border);border-radius:var(--r);padding:14px;box-shadow:var(--sh)">'
    +'<div style="font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.12em;color:var(--muted);margin-bottom:8px">📊 Ventes par journée</div>'
    +'<div id="bilanTip" style="font-size:11px;font-weight:700;color:var(--accent);min-height:16px;margin-bottom:6px;opacity:0;transition:opacity .15s;text-align:center"></div>'
    +'<svg viewBox="0 0 '+W+' '+H+'" width="100%" height="120" preserveAspectRatio="none" style="display:block;border-radius:8px;background:var(--bg)">'+bars+'</svg>'
    +'</div>';
}

function calcBilan(){
  let actives=[...S.journees].filter(j=>(j.total_vendu||0)>0);
  actives.sort((a,b)=>new Date(b.date_journee)-new Date(a.date_journee));
  if(_daysN>0)actives=actives.slice(0,_daysN);
  if(!actives.length){toast('Aucune journée avec activité','info');document.getElementById('bilanResult').style.display='none';return;}
  let tV=0,tCA=0,tMe=0,tL=0,tEnt=0;
  actives.forEach(j=>{tV+=j.total_vendu||0;tCA+=j.total_fcfa||0;tMe+=j.commission_vendeur||0;tL+=j.commission_leader||0;tEnt+=j.part_entreprise_nette||0;});
  const label=_daysN?actives.length+' journée(s) avec activité':'Toutes les journées';
  document.getElementById('bilanKPI').innerHTML=
    '<div class="kpi dark wide"><div class="kpi-val">'+fmt(tMe)+' F</div><div class="kpi-lbl">💚 Mes gains — '+label+'</div></div>'
    +'<div class="kpi"><div class="kpi-val" style="color:var(--blue)">'+tV+'</div><div class="kpi-lbl">Unités vendues</div></div>'
    +'<div class="kpi"><div class="kpi-val" style="color:var(--ink)">'+fmt(tCA)+' F</div><div class="kpi-lbl">Total collecté</div></div>'
    +'<div class="kpi"><div class="kpi-val" style="color:var(--red)">'+fmt(tEnt)+' F</div><div class="kpi-lbl">Part entreprise</div></div>';
  const sorted=[...actives].sort((a,b)=>new Date(a.date_journee)-new Date(b.date_journee));
  document.getElementById("bilanChart").innerHTML=buildBilanChart(sorted);
  document.getElementById('bilanDays').innerHTML=sorted.map(j=>'<div class="hentry" style="margin-bottom:7px;padding:10px 12px"><div class="hrow"><div style="font-size:11px;font-weight:700;color:var(--muted);flex:1">'+(j.date_label||j.date_journee)+'</div><div style="display:flex;gap:8px;align-items:center;flex-shrink:0"><span style="font-family:\'JetBrains Mono\',monospace;font-size:11px;color:var(--blue)">'+j.total_vendu+' u.</span><span style="font-family:\'JetBrains Mono\',monospace;font-size:13px;font-weight:800;color:var(--accent)">'+fmt(j.commission_vendeur)+' F</span></div></div></div>').join('');
  document.getElementById('bilanResult').style.display='block';
  document.getElementById('bilanResult').scrollIntoView({behavior:'smooth',block:'start'});
  window._bilan={actives,tV,tCA,tMe,tL,tEnt,label,n:actives.length};
}
function sendBilanWA(){
  const b=window._bilan;if(!b){toast("Calculez d'abord",'error');return;}
  const ts=new Date().toLocaleDateString('fr-FR')+' à '+new Date().toLocaleTimeString('fr-FR',{hour:'2-digit',minute:'2-digit'});
  let txt='🧴 *'+(S.profile?.nom||'Vendeur')+' — Bilan ('+b.label+')*\n📅 '+ts+'\n\n'
    +'━━━━━━━━━━━━━━━━━━\n📊 *RÉSUMÉ*\n• Unités vendues   : '+b.tV+'\n• Total collecté   : '+fmt(b.tCA)+' F\n'
    +'• 💚 Mes gains     : '+fmt(b.tMe)+' F\n• Entreprise       : '+fmt(b.tEnt)+' F\n\n'
    +'━━━━━━━━━━━━━━━━━━\n📋 *DÉTAIL*\n';
  b.actives.forEach(j=>{txt+='• '+(j.date_label||j.date_journee)+' : '+j.total_vendu+' u. → '+fmt(j.commission_vendeur)+' F\n';});
  txt+='━━━━━━━━━━━━━━━━━━';
  document.getElementById('bilanWATxt').textContent=txt;window._bilanTxt=txt;openMod('mBilanWA');
}
function doSendBilanWA(){window.open('https://wa.me/?text='+encodeURIComponent(window._bilanTxt),'_blank');closeMod('mBilanWA');toast('📤 Bilan envoyé !','success');}

// ════ CHANGEMENT PIN ════
function pcK(k){if(pcBuf.length>=4)return;pcBuf+=k;renderPinDots('pc',pcBuf);if(pcBuf.length===4)setTimeout(processPc,200);}
function pcD(){pcBuf=pcBuf.slice(0,-1);renderPinDots('pc',pcBuf);}
function renderPinDots(p,buf){for(let i=0;i<4;i++)document.getElementById(p+i).classList.toggle('on',i<buf.length);}
async function processPc(){
  const err=document.getElementById('pcErr');err.textContent='';err.style.color='var(--red)';
  if(pcStage==='old'){
    const h=await hashPin(pcBuf);if(h!==S.profile.pin_hash){err.textContent='Ancien PIN incorrect.';pcBuf='';renderPinDots('pc',pcBuf);return;}
    pcNew='';pcBuf='';pcStage='new';document.getElementById('pcStep').textContent='Entrez votre nouveau PIN';renderPinDots('pc','');
  }else if(pcStage==='new'){
    pcNew=pcBuf;pcBuf='';pcStage='confirm';document.getElementById('pcStep').textContent='Confirmez le nouveau PIN';renderPinDots('pc','');
  }else if(pcStage==='confirm'){
    if(pcBuf!==pcNew){err.textContent='Les PINs ne correspondent pas.';pcBuf='';pcNew='';pcStage='old';document.getElementById('pcStep').textContent='Entrez votre ancien PIN';renderPinDots('pc','');return;}
    showLoad('Mise à jour du PIN…');const h=await hashPin(pcBuf);
    const{error}=await sb.from('users').update({pin_hash:h}).eq('id',S.profile.id);
    hideLoad();if(error){err.textContent='Erreur : '+error.message;pcBuf='';pcStage='old';return;}
    S.profile.pin_hash=h;localStorage.setItem('bf_session',JSON.stringify({profile:S.profile}));
    pcBuf='';pcNew='';pcStage='old';document.getElementById('pcStep').textContent='Entrez votre ancien PIN';renderPinDots('pc','');
    err.style.color='var(--accent)';err.textContent='✅ PIN changé avec succès !';toast('✅ Nouveau PIN enregistré','success');
  }
}

// ════ BACKUP ════
function exportBackup(){
  const data={exportDate:new Date().toISOString(),vendeur:S.profile?.nom,journees:S.journees};
  const blob=new Blob([JSON.stringify(data,null,2)],{type:'application/json'});
  const url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;
  a.download='backup_'+new Date().toLocaleDateString('fr-FR').replace(/\//g,'-')+'.json';
  a.click();URL.revokeObjectURL(url);toast('✅ Backup exporté','success');
}

// ════ PERSISTANCE LOCALE ════
function saveLocal(){
  if(S.started)localStorage.setItem('bf_cur',JSON.stringify({started:S.started,stock:S.stock,N:S.N,openTs:S.openTs,userId:S.profile?.id}));
  else localStorage.removeItem('bf_cur');
}
function restoreCurrent(){
  try{
    const cur=JSON.parse(localStorage.getItem('bf_cur'));
    if(cur&&cur.started&&cur.userId===S.profile?.id){
      S.started=cur.started;S.stock=cur.stock||0;S.N=cur.N||{cash:0,wave:0,orange:0};
      S.openTs=cur.dayOpenTs||Date.now();
      document.getElementById('stockQty').value=S.stock;
      document.getElementById('btnCorrect').style.display='flex';
      startAutoWatch();startSince();upd();toast('↩️ Journée en cours restaurée','info');
    }
  }catch(e){}
}
